import { useEffect, useState } from 'react';
import { Search } from "lucide-react";

export default function Navbar() {
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <header
      className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 ${
        isScrolled ? 'bg-cafebeige shadow-md' : 'bg-transparent'
      } flex items-center justify-between px-6 py-4 min-h-[80px]`}
    >
      {/* Left: Logo */}
      <div className="flex items-center">
        <img src="/logo-edit.svg" alt="Ila Cafe Logo" className="h-16 w-auto" />
      </div>

      {/* Right: Navigation Links + Search */}
      <nav className="flex items-center gap-6 text-sm font-medium text-gray-700">
        <a href="#" className="hover:text-cafegreen">Home</a>
        <a href="#" className="hover:text-cafegreen">About Us</a>
        <a href="#" className="hover:text-cafegreen">Gallery</a>
        <a href="#" className="hover:text-cafegreen">Menu</a>
        <a href="#" className="hover:text-cafegreen">Contact Us</a>
        <button className="hover:text-cafegreen">
          <Search size={20} />
        </button>
      </nav>
    </header>
  );
}
